    <script>
        // ============================================
        // IMMERSIVE FLOWING BACKGROUND SYSTEM
        // ============================================
        const canvas = document.getElementById('livingCanvas');
        const ctx = canvas.getContext('2d');
        const mouseGlow = document.getElementById('mouseGlow');
        const scrollProgress = document.getElementById('scrollProgress');
        const videoOverlay = document.getElementById('videoOverlay');

        // ============================================
        // VIDEO BACKGROUND (autoplay, loop, muted)
        // ============================================
        // Video plays automatically - no scroll control needed

        // Gradient orbs
        const orbs = [
            document.getElementById('orb1'),
            document.getElementById('orb2'),
            document.getElementById('orb3'),
            document.getElementById('orb4'),
            document.getElementById('orb5')
        ];

        let mouseX = window.innerWidth / 2;
        let mouseY = window.innerHeight / 2;
        let targetMouseX = mouseX;
        let targetMouseY = mouseY;
        let scrollY = 0;
        let scrollProgress_val = 0;

        // Resize canvas
        function resizeCanvas() {
            canvas.width = window.innerWidth;
            canvas.height = Math.max(document.body.scrollHeight, window.innerHeight * 5);
        }
        resizeCanvas();
        window.addEventListener('resize', resizeCanvas);

        // Track mouse position with enhanced glow
        document.addEventListener('mousemove', (e) => {
            targetMouseX = e.clientX;
            targetMouseY = e.clientY;
            mouseGlow.style.left = e.clientX + 'px';
            mouseGlow.style.top = e.clientY + 'px';
            mouseGlow.classList.add('active');
        });

        document.addEventListener('mouseleave', () => {
            mouseGlow.classList.remove('active');
        });

        // ============================================
        // SCROLL-REACTIVE ELEMENTS
        // ============================================
        function updateScrollEffects() {
            scrollY = window.scrollY;
            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
            scrollProgress_val = Math.min(scrollY / docHeight, 1);

            // Update scroll progress bar
            scrollProgress.style.height = (scrollProgress_val * 100) + '%';

            // Darken video overlay as user scrolls past hero
            const heroHeight = window.innerHeight;
            const scrollRatio = Math.min(scrollY / heroHeight, 1);
            const overlayOpacity = 0.3 + (scrollRatio * 0.45); // 0.3 at top → 0.75 past hero
            if (videoOverlay) {
                videoOverlay.style.background = `rgba(0, 0, 0, ${overlayOpacity})`;
            }

            // Move gradient orbs based on scroll (parallax effect)
            const parallaxFactor = 0.3;
            orbs.forEach((orb, index) => {
                if (orb) {
                    const speed = (index + 1) * 0.15;
                    const yOffset = scrollY * speed * parallaxFactor;
                    const xOffset = Math.sin(scrollY * 0.001 + index) * 50;
                    orb.style.transform = `translate(${xOffset}px, ${-yOffset}px)`;

                    // Fade orbs based on their position relative to scroll
                    const orbOpacity = 0.3 + (Math.sin(scrollY * 0.002 + index * 0.5) * 0.15);
                    orb.style.opacity = orbOpacity;
                }
            });
        }

        window.addEventListener('scroll', updateScrollEffects);
        updateScrollEffects();

        // ============================================
        // FLOWING PARTICLE SYSTEM
        // ============================================
        // ============================================
        // PERFORMANCE CONFIG - viewport-aware
        // ============================================
        function getParticleConfig() {
            var vw = window.innerWidth;
            var dpr = window.devicePixelRatio || 1;
            if (vw < 480) {
                return { flow: 20, neural: 8, energy: 0, pixelRatio: 1 };
            } else if (vw < 768) {
                return { flow: 40, neural: 15, energy: 2, pixelRatio: 1 };
            } else {
                return { flow: 150, neural: 40, energy: 5, pixelRatio: Math.min(dpr, 2) };
            }
        }

        // ============================================
        // TYPED-ARRAY PARTICLE POOLS (no GC pressure)
        // ============================================
        var MAX_FLOW = 150;
        var MAX_NEURAL = 40;
        var MAX_ENERGY = 5;

        // FlowParticle flat arrays: x, y, baseY, size, speedX, speedY, opacity, pulseSpeed, pulseOffset, colorRatio, currentOpacity
        var fp_x          = new Float32Array(MAX_FLOW);
        var fp_y          = new Float32Array(MAX_FLOW);
        var fp_size       = new Float32Array(MAX_FLOW);
        var fp_speedX     = new Float32Array(MAX_FLOW);
        var fp_speedY     = new Float32Array(MAX_FLOW);
        var fp_opacity    = new Float32Array(MAX_FLOW);
        var fp_pulseSpeed = new Float32Array(MAX_FLOW);
        var fp_pulseOff   = new Float32Array(MAX_FLOW);
        var fp_colorRatio = new Float32Array(MAX_FLOW);
        var fp_curOpa     = new Float32Array(MAX_FLOW);

        // NeuralNode flat arrays: x, y, size, pulsePhase, isOrange (0/1), currentSize
        var nn_x          = new Float32Array(MAX_NEURAL);
        var nn_y          = new Float32Array(MAX_NEURAL);
        var nn_size       = new Float32Array(MAX_NEURAL);
        var nn_pulsePhase = new Float32Array(MAX_NEURAL);
        var nn_isOrange   = new Uint8Array(MAX_NEURAL);
        var nn_curSize    = new Float32Array(MAX_NEURAL);

        // EnergyPulse flat arrays: x, y, targetX, speed, width, opacity, isOrange (0/1)
        var ep_x          = new Float32Array(MAX_ENERGY);
        var ep_y          = new Float32Array(MAX_ENERGY);
        var ep_targetX    = new Float32Array(MAX_ENERGY);
        var ep_speed      = new Float32Array(MAX_ENERGY);
        var ep_width      = new Float32Array(MAX_ENERGY);
        var ep_opacity    = new Float32Array(MAX_ENERGY);
        var ep_isOrange   = new Uint8Array(MAX_ENERGY);

        // Cached dimensions (updated only on resize)
        var cachedCanvasW = canvas.width;
        var cachedCanvasH = canvas.height;

        // ============================================
        // INIT FUNCTIONS (fill typed arrays in-place)
        // ============================================
        function initFlowParticle(i) {
            fp_x[i]          = Math.random() * cachedCanvasW;
            fp_y[i]          = Math.random() * cachedCanvasH;
            fp_size[i]       = Math.random() * 2.5 + 0.5;
            fp_speedX[i]     = (Math.random() - 0.5) * 0.8;
            fp_speedY[i]     = Math.random() * 0.5 + 0.2;
            fp_opacity[i]    = Math.random() * 0.4 + 0.1;
            fp_pulseSpeed[i] = Math.random() * 0.02 + 0.01;
            fp_pulseOff[i]   = Math.random() * Math.PI * 2;
            fp_colorRatio[i] = Math.random();
            fp_curOpa[i]     = fp_opacity[i];
        }

        function initNeuralNode(i) {
            nn_x[i]          = Math.random() * cachedCanvasW;
            nn_y[i]          = Math.random() * cachedCanvasH;
            nn_size[i]       = Math.random() * 3 + 2;
            nn_pulsePhase[i] = Math.random() * Math.PI * 2;
            nn_isOrange[i]   = Math.random() > 0.5 ? 1 : 0;
            nn_curSize[i]    = nn_size[i];
        }

        function initEnergyPulse(i, staggerY) {
            ep_y[i]        = staggerY !== undefined ? staggerY : -100;
            ep_x[i]        = Math.random() * cachedCanvasW;
            ep_targetX[i]  = Math.random() * cachedCanvasW;
            ep_speed[i]    = Math.random() * 3 + 2;
            ep_width[i]    = Math.random() * 200 + 100;
            ep_opacity[i]  = Math.random() * 0.4 + 0.2;
            ep_isOrange[i] = Math.random() > 0.5 ? 1 : 0;
        }

        // ============================================
        // INITIAL POPULATION
        // ============================================
        var particleConfig = getParticleConfig();
        var activeFlow   = particleConfig.flow;
        var activeNeural = particleConfig.neural;
        var activeEnergy = particleConfig.energy;

        for (var i = 0; i < MAX_FLOW;   i++) initFlowParticle(i);
        for (var i = 0; i < MAX_NEURAL; i++) initNeuralNode(i);
        for (var i = 0; i < MAX_ENERGY; i++) initEnergyPulse(i, Math.random() * cachedCanvasH);

        // ============================================
        // MAIN ANIMATION LOOP (optimized)
        // ============================================
        var animationTime = 0;
        var rafId = null;

        function animateLivingBackground() {
            animationTime += 16;
            ctx.clearRect(0, 0, cachedCanvasW, cachedCanvasH);

            // Smooth mouse position
            mouseX += (targetMouseX - mouseX) * 0.08;
            mouseY += (targetMouseY - mouseY) * 0.08;

            // --- Energy pulses (background layer) ---
            for (var i = 0; i < activeEnergy; i++) {
                ep_y[i] += ep_speed[i];
                ep_x[i] += (ep_targetX[i] - ep_x[i]) * 0.01;
                if (ep_y[i] > cachedCanvasH + 100) {
                    initEnergyPulse(i);
                }
                var egr = ctx.createRadialGradient(ep_x[i], ep_y[i], 0, ep_x[i], ep_y[i], ep_width[i]);
                if (ep_isOrange[i]) {
                    egr.addColorStop(0, 'rgba(241,66,11,' + ep_opacity[i] + ')');
                    egr.addColorStop(0.5, 'rgba(241,66,11,' + (ep_opacity[i] * 0.3) + ')');
                } else {
                    egr.addColorStop(0, 'rgba(42,147,193,' + ep_opacity[i] + ')');
                    egr.addColorStop(0.5, 'rgba(42,147,193,' + (ep_opacity[i] * 0.3) + ')');
                }
                egr.addColorStop(1, 'transparent');
                ctx.fillStyle = egr;
                ctx.beginPath();
                ctx.arc(ep_x[i], ep_y[i], ep_width[i], 0, Math.PI * 2);
                ctx.fill();
            }

            // --- Flow particles ---
            var scrollInf = scrollProgress_val;
            for (var i = 0; i < activeFlow; i++) {
                // Update
                fp_x[i] += fp_speedX[i] + Math.sin(animationTime * 0.001 + fp_y[i] * 0.01) * 0.3;
                fp_y[i] += fp_speedY[i];
                fp_curOpa[i] = fp_opacity[i] * (0.5 + Math.sin(animationTime * fp_pulseSpeed[i] + fp_pulseOff[i]) * 0.5);

                // Mouse influence
                var fdx = mouseX - fp_x[i];
                var fdy = (mouseY + scrollY) - fp_y[i];
                var fd  = Math.sqrt(fdx * fdx + fdy * fdy);
                if (fd < 150 && fd > 0) {
                    var ff = (150 - fd) / 150;
                    fp_x[i] -= (fdx / fd) * ff * 2;
                    fp_y[i] -= (fdy / fd) * ff * 2;
                }

                // Wrap around
                if (fp_x[i] < -10) fp_x[i] = cachedCanvasW + 10;
                if (fp_x[i] > cachedCanvasW + 10) fp_x[i] = -10;
                if (fp_y[i] > cachedCanvasH + 10) {
                    fp_y[i] = -10;
                    fp_x[i] = Math.random() * cachedCanvasW;
                }

                // Draw
                var cr = fp_colorRatio[i];
                var fr, fg, fb;
                if (cr < 0.5 - scrollInf * 0.3) {
                    fr = 241; fg = 66; fb = 11;
                } else if (cr > 0.5 + scrollInf * 0.3) {
                    fr = 42; fg = 147; fb = 193;
                } else {
                    fr = 58; fg = 96; fb = 171;
                }
                ctx.fillStyle = 'rgba(' + fr + ',' + fg + ',' + fb + ',' + fp_curOpa[i] + ')';
                ctx.beginPath();
                ctx.arc(fp_x[i], fp_y[i], fp_size[i], 0, Math.PI * 2);
                ctx.fill();
            }

            // --- Neural nodes ---
            for (var i = 0; i < activeNeural; i++) {
                nn_x[i]      += Math.sin(animationTime * 0.0005 + nn_pulsePhase[i]) * 0.2;
                nn_y[i]      += Math.cos(animationTime * 0.0003 + nn_pulsePhase[i]) * 0.2;
                nn_curSize[i] = nn_size[i] * (0.8 + Math.sin(animationTime * 0.002 + nn_pulsePhase[i]) * 0.2);
                var nalpha = 0.3 + Math.sin(animationTime * 0.002 + nn_pulsePhase[i]) * 0.2;
                var ncolor = nn_isOrange[i] ? '241,66,11' : '42,147,193';
                ctx.fillStyle = 'rgba(' + ncolor + ',' + nalpha + ')';
                ctx.beginPath();
                ctx.arc(nn_x[i], nn_y[i], nn_curSize[i], 0, Math.PI * 2);
                ctx.fill();
                ctx.shadowColor = nn_isOrange[i] ? 'rgba(241,66,11,0.5)' : 'rgba(42,147,193,0.5)';
                ctx.shadowBlur = 15;
                ctx.fill();
                ctx.shadowBlur = 0;
            }

            // --- Neural connections ---
            var connectionDist = 200 + scrollProgress_val * 100;
            ctx.lineWidth = 0.5;
            for (var i = 0; i < activeNeural; i++) {
                for (var j = i + 1; j < activeNeural; j++) {
                    var cdx  = nn_x[i] - nn_x[j];
                    var cdy  = nn_y[i] - nn_y[j];
                    var dist = Math.sqrt(cdx * cdx + cdy * cdy);
                    if (dist < connectionDist) {
                        var calpha  = (1 - dist / connectionDist) * 0.15;
                        var cgrad   = ctx.createLinearGradient(nn_x[i], nn_y[i], nn_x[j], nn_y[j]);
                        var color1  = nn_isOrange[i] ? '241,66,11' : '42,147,193';
                        var color2  = nn_isOrange[j] ? '241,66,11' : '42,147,193';
                        cgrad.addColorStop(0, 'rgba(' + color1 + ',' + calpha + ')');
                        cgrad.addColorStop(1, 'rgba(' + color2 + ',' + calpha + ')');
                        ctx.strokeStyle = cgrad;
                        ctx.beginPath();
                        ctx.moveTo(nn_x[i], nn_y[i]);
                        ctx.lineTo(nn_x[j], nn_y[j]);
                        ctx.stroke();
                    }
                }
            }

            // --- Mouse connections to nearby neural nodes ---
            for (var i = 0; i < activeNeural; i++) {
                var mdx  = mouseX - nn_x[i];
                var mdy  = (mouseY + scrollY) - nn_y[i];
                var mdist = Math.sqrt(mdx * mdx + mdy * mdy);
                if (mdist < 200) {
                    var malpha = (1 - mdist / 200) * 0.3;
                    ctx.strokeStyle = 'rgba(255,255,255,' + malpha + ')';
                    ctx.lineWidth = 1;
                    ctx.beginPath();
                    ctx.moveTo(mouseX, mouseY + scrollY);
                    ctx.lineTo(nn_x[i], nn_y[i]);
                    ctx.stroke();
                }
            }

            rafId = requestAnimationFrame(animateLivingBackground);
        }

