        function submitToWaitlist(data) {
            const formUrl = 'https://docs.google.com/forms/d/e/1FAIpQLSei-RHBkOYsm79-4ueVqVSYAhNMrAwjTcoI1wpBpPPAtf2ujg/formResponse';
