            }
            window.pbDemoPlay = function(playerEl) {
                var video = document.getElementById('pbDemoVideo');
                var overlay = document.getElementById('pbDemoOverlay');
                if (!video) return;
                /* If zoomed, tap = exit zoom */
                if (_zoomed) {
                    exitZoom(playerEl, video);
                    return;
                }
                if (!_loaded) {
                    _loaded = true;
                    video.src = MP4;
                    video.load();
                    video.muted = false;
